function buildTechnicalDocumentationPdfDataUrl() {
  const sections = [
    ['title', 'Pallet Check Tool'],
    ['body', 'Technical documentation for maintaining and editing the standalone HTML application. This PDF is generated from content embedded in the HTML file, so it works when the tool is shared as one file.'],
    ['h1', '1. Application overview'],
    ['h2', 'Purpose'],
    ['body', 'Pallet Check Tool supports a warehouse pallet checking workflow. The operator imports system data, scans or types a Pallet ID, then confirms SKU or EAN codes from the physical pallet. The tool validates membership, tracks progress, highlights rows, records wrong scans and stores work locally in the browser.'],
    ['h2', 'Distribution model'],
    ['body', 'The application is intentionally local. It uses one HTML file and browser localStorage. It does not use a backend, database, CDN, package manager, build step or internet connection. This makes distribution simple, but each user has a separate local state.'],
    ['h1', '2. File structure'],
    ['body', 'The HTML file contains four layers: visible HTML structure, CSS styles, JavaScript workflow logic and the built-in EAN-to-SKU map. Use Ctrl+F and search stable identifiers rather than visible labels.'],
    ['code', 'Useful search terms:\nDEFAULT_STATE\nDEFAULT_MAPPING\nparseRawData\nappendBatch\nsearchPallet\nrenderResults\nrenderRowTable\nstartScanWorkflow\nhandleSkuScan\naddWrongScan\nrenderCompletedHistory\nbindEvents'],
    ['h1', '3. State and settings'],
    ['h2', 'STORAGE_KEY'],
    ['body', 'Controls the localStorage key. Changing it forces a practical data reset because the browser will not load the previous saved state. Use this only when a structural state change makes old data unsafe.'],
    ['h2', 'DEFAULT_MAPPING'],
    ['body', 'Defines default source columns for qty, sku, pallet and container. Values are 1-based column numbers, matching how users count Excel columns. getColumnIndexes converts them to JavaScript indexes.'],
    ['h2', 'DEFAULT_STATE'],
    ['body', 'Defines the startup model: imported rows, batch count, mapping, completed pallet history, pallet activity, wrong scans, scan mode, manual modes, focus lock, sound setting, custom EAN map and last import date.'],
    ['h1', '4. Import pipeline'],
    ['h2', 'parseRawData(rawText)'],
    ['body', 'Converts pasted tab-separated system data into internal row objects with sku, qty, palletId and containerId. Edit this function first if the source export format changes.'],
    ['h2', 'appendBatch(rows, sourceLabel)'],
    ['body', 'Validates parsed rows, removes duplicates, appends unique rows to state.rows, increments batchCount, updates lastImportDate, saves state and refreshes counters. This is the main import commit point.'],
    ['h2', 'buildRowKey(row)'],
    ['body', 'Defines duplicate detection. Current logic uses SKU, quantity, Pallet ID and Container ID. Change this function if duplicate rules change operationally.'],
    ['h1', '5. Pallet search workflow'],
    ['h2', 'searchPallet()'],
    ['body', 'Main entry point after a pallet scan or manual submit. It validates the input, checks whether data exists, protects unfinished active pallets, handles suffix search, searches exact Pallet ID, checks Container ID matches and renders results.'],
    ['h2', 'No-result logic'],
    ['body', 'If no row matches, the tool checks hasImportedToday(). If no batch was imported today, it shows a daily import warning instead of treating the scan as an operator error. If data is current, the unknown scan is logged.'],
    ['h1', '6. Result rendering'],
    ['h2', 'renderResults(rows, palletId, options)'],
    ['body', 'Controls the result area after search. It stores currentView, activates pallet view, updates title and metadata, renders the table, refreshes duplicate warnings and starts the scan workflow when rows exist.'],
    ['h2', 'renderRowTable(rows)'],
    ['body', 'Builds visible table rows. It writes SKU, EAN, quantity, Pallet ID and Container ID cells and applies progress classes such as scan-row-progress, scan-row-done and scan-row-latest. Any table column change must be reflected here.'],
    ['h2', 'renderCurrentMeta(rows, palletId, labelText)'],
    ['body', 'Calculates lightweight summary values for the current pallet. These values support the right-side statistic cards and result metadata.'],
    ['h1', '7. Scan workflow'],
    ['h2', 'scanState'],
    ['body', 'Runtime model for the active pallet. It stores activePalletId, mode, requirements, scannedCounts, completionLogged, status and lastScannedSku. It is not intended as long-term storage.'],
    ['h2', 'startScanWorkflow(rows, palletId)'],
    ['body', 'Builds scan requirements for the active pallet. In SKU mode, each unique SKU requires one confirmation. In Quantity mode, each SKU requires the quantity from the source data.'],
    ['h2', 'handleSkuScan()'],
    ['body', 'Processes each SKU or EAN scan. It resolves EAN to SKU, checks whether the SKU belongs to the active pallet, prevents over-scanning, updates counts, refreshes the table and completes the pallet when requirements are met.'],
    ['h2', 'evaluatePalletStatus()'],
    ['body', 'Returns the current operational state. It feeds the status badge, progress text and completion behavior. Change this carefully because it affects workflow completion.'],
    ['h1', '8. EAN and SKU matching'],
    ['h2', 'rebuildEanMaps()'],
    ['body', 'Builds lookup structures from the active EAN map. It supports full EAN, shortened EAN and reverse display from SKU to EAN. Run this after loading custom EAN data.'],
    ['h2', 'resolveSkuOrEan(value)'],
    ['body', 'Normalizes scanned input and tries full EAN, shortened EAN and raw SKU. Edit this function if physical label format or scan format changes.'],
    ['h2', 'stripEanPrefix(ean)'],
    ['body', 'Removes the first two characters from an EAN for short-code matching. Keep this only if it reflects the actual label convention.'],
    ['h1', '9. Wrong Scan Log'],
    ['h2', 'addWrongScan(type, value, details)'],
    ['body', 'Creates a new wrong scan entry with type, scanned value, detail text and timestamp. Newest entries appear first. The current retention limit is controlled by slice(0, 100).'],
    ['h2', 'renderWrongScanLog()'],
    ['body', 'Renders the log list with pagination. Page size is controlled by ACTIVITY_PAGE_SIZE. Current operational page size is 20 entries.'],
    ['h1', '10. Completed Pallets History'],
    ['h2', 'logCompletedPallet()'],
    ['body', 'Writes a completed pallet record after the workflow reaches complete status. The record includes pallet ID, timestamp, mode and progress summary.'],
    ['h2', 'renderCompletedHistory()'],
    ['body', 'Renders completed pallet history with the same pagination helper used by Wrong Scan Log. Retention is controlled by slice(0, 100).'],
    ['h1', '11. UI and CSS'],
    ['body', 'Important CSS selectors: side-tab-panel for top-left tabs, doc-download-card for this download area, search-card for the main work area, scan-panel for SKU scanning, table-wrap for the result table, meta-grid and meta-card for right-side statistics, stacked-panels for lower utility panels, workflow-modal for completion popup and activity-pagination for log pagination.'],
    ['h1', '12. Messages, focus and sound'],
    ['body', 'setStatus controls inline messages. showWorkflowModal controls larger workflow feedback. getActiveInput and queueFocusActiveInput keep scanner focus in the correct field. beep(type) handles success, error and completion sounds. Manual modes reduce automatic focus and submit behavior.'],
    ['h1', '13. Change recipes'],
    ['body', 'Change default columns in DEFAULT_MAPPING. Change import format in parseRawData. Change duplicate detection in buildRowKey. Change pallet lookup in searchPallet. Change SKU/EAN scan behavior in handleSkuScan. Change completion rules in startScanWorkflow and evaluatePalletStatus. Change EAN recognition in resolveSkuOrEan or stripEanPrefix.'],
    ['h1', '14. Test checklist'],
    ['body', 'After every functional change: refresh with Ctrl+F5, Clear All, import a small known batch, search an existing pallet, scan a valid SKU/EAN, scan an invalid SKU/EAN, check Wrong Scan Log, complete the pallet, check Completed Pallets History, refresh again and confirm localStorage restored data. Then share only the HTML file and confirm this PDF downloads.'],
    ['h1', '15. Mental model'],
    ['body', 'Import data -> state.rows. Search pallet -> currentView.rows. Start scan -> scanState.requirements. Scan SKU/EAN -> scanState.scannedCounts. Update status -> table highlight and progress. Complete pallet -> completedHistory. Wrong scan -> wrongScans. Save -> localStorage.']
  ];

  const pageWidth = 595.28;
  const pageHeight = 841.89;
  const left = 54;
  const right = 54;
  const top = 64;
  const bottom = 58;
  const maxWidth = pageWidth - left - right;
  const pages = [];
  let lines = [];
  let y = pageHeight - top;

  function cleanText(value) {
    return String(value).replace(/[\u2013\u2014]/g, '-').replace(/[\u2018\u2019]/g, "'").replace(/[\u201c\u201d]/g, '"');
  }

  function wrap(text, fontSize, maxCharsOverride) {
    const maxChars = maxCharsOverride || Math.max(42, Math.floor(maxWidth / (fontSize * 0.52)));
    const words = cleanText(text).split(/\s+/);
    const out = [];
    let line = '';
    words.forEach((word) => {
      const test = line ? line + ' ' + word : word;
      if (test.length > maxChars && line) {
        out.push(line);
        line = word;
      } else {
        line = test;
      }
    });
    if (line) out.push(line);
    return out;
  }

  function newPage() {
    if (lines.length) pages.push(lines);
    lines = [];
    y = pageHeight - top;
  }

  function addLine(text, size, font, color, gapAfter) {
    if (y < bottom + 22) newPage();
    lines.push({ text: cleanText(text), size, font, color, x: left, y });
    y -= size + (gapAfter || 5);
  }

  function addBlock(type, text) {
    if (type === 'title') {
      addLine(text, 24, 'F2', '0 0.36 0.67', 14);
      return;
    }
    if (type === 'h1') {
      y -= 6;
      addLine(text, 15, 'F2', '0.06 0.16 0.28', 8);
      return;
    }
    if (type === 'h2') {
      addLine(text, 11.5, 'F2', '0 0.36 0.67', 5);
      return;
    }
    if (type === 'code') {
      text.split('\n').forEach((line) => addLine(line, 8.2, 'F3', '0.08 0.15 0.24', 3));
      y -= 4;
      return;
    }
    wrap(text, 9.3).forEach((line) => addLine(line, 9.3, 'F1', '0.09 0.14 0.22', 4));
    y -= 4;
  }

  sections.forEach(([type, text]) => addBlock(type, text));
  if (lines.length) pages.push(lines);

  function esc(s) {
    return String(s).replace(/\\/g, '\\\\').replace(/\(/g, '\\(').replace(/\)/g, '\\)');
  }

  const objects = [];
  function obj(s) { objects.push(s); return objects.length; }
  const catalogId = obj('');
  const pagesId = obj('');
  const font1Id = obj('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>');
  const font2Id = obj('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>');
  const font3Id = obj('<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>');
  const pageIds = [];
  pages.forEach((pageLines, index) => {
    const content = pageLines.map((line) => `BT /${line.font} ${line.size} Tf ${line.color} rg ${line.x} ${line.y.toFixed(2)} Td (${esc(line.text)}) Tj ET`).join('\n') + `\nBT /F1 7.5 Tf 0.40 0.47 0.55 rg ${left} 28 Td (Pallet Check Tool - Technical Documentation) Tj ET\nBT /F1 7.5 Tf 0.40 0.47 0.55 rg 505 28 Td (Page ${index + 1}) Tj ET`;
    const contentId = obj(`<< /Length ${content.length} >>\nstream\n${content}\nendstream`);
    const pageId = obj(`<< /Type /Page /Parent ${pagesId} 0 R /MediaBox [0 0 ${pageWidth} ${pageHeight}] /Resources << /Font << /F1 ${font1Id} 0 R /F2 ${font2Id} 0 R /F3 ${font3Id} 0 R >> >> /Contents ${contentId} 0 R >>`);
    pageIds.push(pageId);
  });
  objects[catalogId - 1] = `<< /Type /Catalog /Pages ${pagesId} 0 R >>`;
  objects[pagesId - 1] = `<< /Type /Pages /Kids [${pageIds.map((id) => id + ' 0 R').join(' ')}] /Count ${pageIds.length} >>`;
  let pdf = '%PDF-1.4\n';
  const offsets = [0];
  objects.forEach((body, i) => {
    offsets.push(pdf.length);
    pdf += `${i + 1} 0 obj\n${body}\nendobj\n`;
  });
  const xref = pdf.length;
  pdf += `xref\n0 ${objects.length + 1}\n0000000000 65535 f \n`;
  offsets.slice(1).forEach((offset) => { pdf += String(offset).padStart(10, '0') + ' 00000 n \n'; });
  pdf += `trailer\n<< /Size ${objects.length + 1} /Root ${catalogId} 0 R >>\nstartxref\n${xref}\n%%EOF`;
  return 'data:application/pdf;base64,' + btoa(pdf);
}

function applyTechnicalDocumentationPdfDownload() {
  const link = document.querySelector('.doc-download-card .doc-download-link');
  if (!link) return;
  link.textContent = 'Download technical documentation (PDF)';
  link.download = 'Pallet_Check_Tool_Technical_Documentation.pdf';
  link.addEventListener('click', () => {
    link.href = buildTechnicalDocumentationPdfDataUrl();
  });
}
